class MagixItemSelector{constructor(e){this.options=Object.assign({searchInputId:"ajaxSearchInput",searchResultsId:"ajaxSearchResults",selectedListId:"selectedItemsList",countBadgeId:"countSelected",searchUrl:"",saveUrl:"",inputName:"items[]",minSearchLength:2,token:"",renderResultItem:e=>`<span>${e.name}</span>`,renderAddedItem:e=>`<span>${e.name}</span>`},e),this.searchInput=document.getElementById(this.options.searchInputId),this.searchResults=document.getElementById(this.options.searchResultsId),this.selectedList=document.getElementById(this.options.selectedListId),this.countBadge=document.getElementById(this.options.countBadgeId),this.searchTimeout=null,this.searchInput&&this.selectedList?(this.initEvents(),this.initSortable()):console.error("MagixItemSelector: Éléments DOM manquants.")}initEvents(){this.searchInput.addEventListener("input",(()=>{clearTimeout(this.searchTimeout);const e=this.searchInput.value.trim();e.length<this.options.minSearchLength?this.searchResults.style.display="none":this.searchTimeout=setTimeout((()=>this.fetchResults(e)),300)})),document.addEventListener("click",(e=>{this.searchInput.contains(e.target)||this.searchResults.contains(e.target)||(this.searchResults.style.display="none")})),this.selectedList.addEventListener("click",(e=>{const t=e.target.closest(".btn-remove");t&&(t.closest("li").remove(),this.updateCountAndSave())}))}initSortable(){"undefined"!=typeof Sortable?new Sortable(this.selectedList,{animation:150,handle:".cursor-move",ghostClass:"bg-warning",onEnd:()=>{this.updateCountAndSave()}}):console.warn("MagixItemSelector: Sortable.js n'est pas chargé.")}async fetchResults(e){try{const t=await fetch(this.options.searchUrl+encodeURIComponent(e)),s=await t.json();this.searchResults.innerHTML="";const n=s.filter((e=>{const t=e.id_product||e.id_pages||e.id_cat||e.id;return!this.selectedList.querySelector(`li[data-id="${t}"]`)}));0===n.length?this.searchResults.innerHTML='<div class="list-group-item text-muted small">Aucun nouveau résultat trouvé.</div>':n.forEach((e=>{const t=e.id_product||e.id_pages||e.id_cat||e.id,s=document.createElement("a");s.href="javascript:void(0)",s.className="list-group-item list-group-item-action",s.innerHTML=this.options.renderResultItem(e),s.addEventListener("click",(()=>this.addItemToList(e,t))),this.searchResults.appendChild(s)})),this.searchResults.style.display="block"}catch(e){console.error("Erreur lors de la recherche AJAX",e)}}addItemToList(e,t){const s=document.createElement("li");s.className="list-group-item d-flex justify-content-between align-items-center bg-light border-bottom cursor-move",s.setAttribute("data-id",t),s.innerHTML=`\n            <input type="hidden" name="${this.options.inputName}" value="${t}">\n            ${this.options.renderAddedItem(e)}\n            <button type="button" class="btn btn-sm btn-outline-danger btn-remove ms-2" title="Retirer"><i class="bi bi-x-lg"></i></button>\n        `,this.selectedList.appendChild(s),this.searchInput.value="",this.searchResults.style.display="none",this.updateCountAndSave()}async updateCountAndSave(){this.countBadge&&(this.countBadge.textContent=this.selectedList.children.length);const e=new FormData;e.append("hashtoken",this.options.token);const t=this.selectedList.querySelectorAll(`input[name="${this.options.inputName}"]`);0===t.length?e.append(this.options.inputName,""):t.forEach((t=>e.append(this.options.inputName,t.value)));try{const t=await fetch(this.options.saveUrl,{method:"POST",body:e,headers:{"X-Requested-With":"XMLHttpRequest"}}),s=await t.json();"undefined"!=typeof MagixToast&&(s.status||s.success?MagixToast.success(s.message||"Mise à jour réussie."):MagixToast.error(s.message||"Erreur lors de la sauvegarde."))}catch(e){console.error("Erreur de sauvegarde",e),"undefined"!=typeof MagixToast&&MagixToast.error("Erreur réseau.")}}}